solidity_before:
struct Op { bool done; uint256 readyTimestamp; }
mapping(bytes32 => Op) ops;
function propose(bytes32 mode, bytes calldata data, uint256 delay) external onlyProposer returns (bytes32 id) {
    require(delay >= minDelay);
    id = keccak256(abi.encode(mode, keccak256(data)));
    require(ops[id].readyTimestamp == 0);
    ops[id] = Op(false, block.timestamp + delay);
    emit Proposed(id, mode, data, block.timestamp + delay);
}

yul_optimized:
function propose(bytes32 mode, bytes calldata executionData, uint256 delay)
    public virtual onlyRole(PROPOSER_ROLE) returns (bytes32 id)
{
    LibERC7579.decodeBatchAndOpData(executionData);
    uint256 t = minDelay();
    assembly {
        if shr(254, delay) {
            mstore(0x00, 0xd1efaf25) // TimelockDelayOverflow()
            revert(0x1c, 0x04)
        }
        if lt(delay, t) {
            mstore(0x00, 0x54336609) // TimelockInsufficientDelay(uint256,uint256)
            mstore(0x20, delay)
            mstore(0x40, t)
            revert(0x1c, 0x44)
        }
        let m := mload(0x40)
        calldatacopy(add(m, 0x80), executionData.offset, executionData.length)
        mstore(0x00, mode)
        mstore(0x20, keccak256(add(m, 0x80), executionData.length))
        id := keccak256(0x00, 0x40)
        // Operation slot: keccak256(id || _TIMELOCK_SLOT) using 0x29 = 41 bytes
        mstore(0x09, _TIMELOCK_SLOT)
        mstore(0x00, id)
        let s := keccak256(0x00, 0x29)
        if sload(s) {
            mstore(0x00, 0xd639b0bf) // TimelockInvalidOperation
            mstore(0x20, id)
            mstore(0x40, 1) // expectedStates bitmap = 1 << Unset
            revert(0x1c, 0x44)
        }
        let r := add(delay, timestamp()) // readyTimestamp
        sstore(s, shl(1, r)) // done=0 in bit 0, ts in bits [1..255]
        // Emit Proposed event with executionData padded to 32 bytes
        mstore(m, mode)
        mstore(add(m, 0x20), 0x60)
        mstore(add(m, 0x40), r)
        mstore(add(m, 0x60), executionData.length)
        mstore(add(add(m, 0x80), executionData.length), 0)
        log2(m, add(0x80, and(not(0x1f), add(0x1f, executionData.length))),
            _PROPOSED_EVENT_SIGNATURE, id)
    }
}

function _execute(bytes32 mode, bytes calldata executionData, Call[] calldata calls, bytes calldata opData)
    internal virtual override
{
    if (!hasRole(OPEN_ROLE_HOLDER, EXECUTOR_ROLE)) _checkRole(EXECUTOR_ROLE);
    bytes32 id;
    uint256 s;
    assembly {
        calldatacopy(mload(0x40), executionData.offset, executionData.length)
        mstore(0x00, mode)
        mstore(0x20, keccak256(mload(0x40), executionData.length))
        id := keccak256(0x00, 0x40)
        mstore(0x09, _TIMELOCK_SLOT)
        mstore(0x00, id)
        s := keccak256(0x00, 0x29)
        let p := sload(s)
        // Ready iff: not done (bit 0 == 0) AND non-zero AND timestamp >= ts
        if or(or(and(1, p), iszero(p)), lt(timestamp(), shr(1, p))) {
            mstore(0x00, 0xd639b0bf)
            mstore(0x20, id)
            mstore(0x40, 4) // 1 << Ready
            revert(0x1c, 0x44)
        }
        if iszero(lt(opData.length, 0x20)) {
            let b := calldataload(opData.offset)
            mstore(0x00, b)
            // Predecessor must be done (bit 0 == 1) OR be zero (no predecessor)
            if iszero(or(iszero(b), and(1, sload(keccak256(0x00, 0x29))))) {
                mstore(0x00, 0x90a9a618) // TimelockUnexecutedPredecessor
                mstore(0x20, b)
                revert(0x1c, 0x24)
            }
        }
    }
    _execute(calls, id);
    assembly {
        // Recheck for reentrancy
        let p := sload(s)
        if or(or(and(1, p), iszero(p)), lt(timestamp(), shr(1, p))) {
            mstore(0x00, 0xd639b0bf)
            mstore(0x20, id)
            mstore(0x40, 4)
            revert(0x1c, 0x44)
        }
        sstore(s, or(1, p)) // Set done bit, preserve ts
    }
}
